//go:build wireinject

package main

import (
	"context"

	"github.com/google/wire"
	"github.com/openmeterio/openmeter/app/common"
	"github.com/openmeterio/openmeter/app/config"
)

func initializeApplication(ctx context.Context, conf config.Configuration) (Application, func(), error) {
	wire.Build(
		common.NewMyWorker, // provider set from app/common only
	)
	return Application{}, nil, nil
}

package main

import (
	"context"

	"github.com/redpanda-data/benthos/v4/public/service"

	_ "github.com/openmeterio/openmeter/collector/benthos/bloblang"
	_ "github.com/openmeterio/openmeter/collector/benthos/input"
)

func main() {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	service.RunCLI(ctx)
}

import migrate "github.com/openmeterio/openmeter/tools/migrate"

cfg := migrate.OMMigrationsConfig{DatabaseURL: conf.Postgres.URL()}
if err := migrate.Migrate(ctx, cfg); err != nil {
	return fmt.Errorf("run migrations: %w", err)
}
